const crypto = require('crypto');
const secret = process.env.VIP_UNLOCK_SECRET;
if (!secret || String(secret).trim() === '') {
  throw new Error('Defina VIP_UNLOCK_SECRET no n8n (igual à Vercel).');
}
const ttlMs = 30 * 24 * 60 * 60 * 1000;
const exp = Date.now() + ttlMs;
const payload = Buffer.from(JSON.stringify({ exp }), 'utf8').toString('base64url');
const sig = crypto.createHmac('sha256', String(secret).trim()).update(payload).digest('base64url');
const token = `${payload}.${sig}`;
let siteBase = String(process.env.VIP_SITE_BASE || 'https://perfilcarol.vercel.app').trim();
while (siteBase.endsWith('/')) siteBase = siteBase.slice(0, -1);
const vipGrantLink = `${siteBase}/api/vip/grant?t=${encodeURIComponent(token)}`;
const item = $input.first().json;
const body = item.body && typeof item.body === 'object' ? item.body : item;
return [{
  json: {
    vipGrantLink,
    transacaoId: body.id,
    value: body.value,
    status: body.status,
    end_to_end_id: body.end_to_end_id || null
  }
}];
